import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { ArrowLeft, Info, MessageSquare, Users } from 'lucide-react';
import { useQuery, useMutation } from "convex/react";
import { api } from "../../../convex/_generated/api";
import { isConvexAvailable } from '../../config/convex';
import ChatInput from './ChatInput';
import SeshNxEmbedModal from '../SeshNxEmbedModal';
import MessageBubble from './message/MessageBubble';
import ForwardMessageModal from './message/ForwardMessageModal';
import PresenceIndicator, { StatusBadge } from './PresenceIndicator';
import { useUserPresence } from '../../hooks/usePresence';
import { useReadReceipts } from '../../hooks/useReadReceipts';
import { useTypingIndicator, formatTypingUsers } from '../../hooks/useTypingIndicator';
import getLinkPreview from '../../utils/linkPreview';
import UserAvatar from '../shared/UserAvatar';
import { useLanguage } from '../../contexts/LanguageContext';
import type { MessageBubbleProps } from './message/MessageBubble';

/**
 * Active chat interface
 */
interface ActiveChat {
    id: string;
    type?: 'direct' | 'group';
    uid?: string;
    name?: string;
    n?: string;
    photo?: string;
    role?: string;
}

/**
 * Embed modal state interface
 */
interface EmbedModalState {
    isOpen: boolean;
    url: string;
    previewData: any;
}

/**
 * ChatWindow props
 */
export interface ChatWindowProps {
    user?: any;
    userData?: any;
    subProfiles?: Record<string, any>;
    activeChat?: ActiveChat | null;
    conversations?: any[];
    onBack?: () => void;
    toggleDetails?: () => void;
    openPublicProfile?: (uid: string, name?: string) => void;
}

/**
 * Message interface (matches Convex format)
 */
interface ChatMessage {
    id: string;
    b?: string; // body/text
    s?: string; // sender id
    n?: string; // name
    photo?: string; // sender photo
    t?: number; // timestamp
    edited?: boolean;
    editedAt?: number;
    deleted?: boolean;
    deletedForAll?: boolean;
    deletedFor?: Record<string, boolean>;
    media?: any;
    replyTo?: any;
    reactions?: Record<string, string[] | Record<string, boolean>>;
}

export default function ChatWindow({ user, userData, subProfiles, activeChat, conversations, onBack, toggleDetails, openPublicProfile }: ChatWindowProps) {
    const { t } = useLanguage();
    const [linkPreviewData, setLinkPreviewData] = useState<Record<string, any>>({});
    const [embedModal, setEmbedModal] = useState<EmbedModalState>({ isOpen: false, url: '', previewData: null });
    const [replyingTo, setReplyingTo] = useState<ChatMessage | null>(null);
    const [editingMessage, setEditingMessage] = useState<ChatMessage | null>(null);
    const [forwardingMessage, setForwardingMessage] = useState<ChatMessage | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const chatId = activeChat?.id;
    const chatName = activeChat?.name || activeChat?.n || t('unknownUser');

    // Normalize user ID for backward compatibility
    const userId = user?.id || user?.uid;

    // Get other user's UID for direct chats (for presence and read receipts)
    const otherUserId = useMemo(() => {
        if (activeChat?.type === 'group') return null;
        if (activeChat?.uid) return activeChat.uid;
        if (chatId && chatId.includes('_')) {
            const parts = chatId.split('_');
            return parts.find(id => id !== userId);
        }
        return null;
    }, [activeChat, chatId, userId]);

    // Presence tracking
    const { online, lastSeen, loading: presenceLoading } = useUserPresence(otherUserId);

    // Read receipts tracking
    const {
        markAsRead,
        hasCurrentUserRead,
        isMessageRead,
        myLastRead
    } = useReadReceipts(chatId, userId);

    // Typing indicator tracking
    const { typingUsers, setTyping, clearTyping } = useTypingIndicator(
        chatId,
        userId,
        userData?.firstName || 'User'
    );

    // FIX: Determine Convex availability directly.
    // Removing useMemo prevents the "Cannot access before initialization" error.
    const convexAvailable = isConvexAvailable();

    const messagesQuery = useMemo(() => {
        return chatId && convexAvailable ? { chatId, limit: 100 } : "skip";
    }, [chatId, convexAvailable]);

    // Query for group chat members
    const chatMembersQuery = useMemo(() => {
        return chatId && convexAvailable && activeChat?.type === 'group' ? { chatId } : "skip";
    }, [chatId, convexAvailable, activeChat?.type]);

    const chatMembersData = useQuery(
        api.conversations.getChatMembers,
        chatMembersQuery
    );

    // Extract member user IDs from chat members data
    const groupMemberIds = useMemo(() => {
        if (!chatMembersData) return [];
        return chatMembersData.map((m: any) => m.userId);
    }, [chatMembersData]);

    // Fetch messages from Convex (automatically reactive)
    // Hook must always be called, but we skip if Convex not available
    const messagesData = useQuery(
        api.messages.getMessages,
        messagesQuery
    );

    // Transform Convex messages to match existing format
    const messages = useMemo(() => {
        if (!messagesData) return [];

        return messagesData.map((msg: any): ChatMessage => ({
            id: msg._id,
            b: msg.content || '',
            s: msg.senderId,
            n: msg.senderName,
            photo: msg.senderPhoto || '',
            t: msg.timestamp,
            edited: msg.edited || false,
            editedAt: msg.editedAt,
            deleted: msg.deleted || false,
            deletedForAll: msg.deletedForAll || false,
            media: msg.media,
            replyTo: msg.replyTo,
            reactions: msg.reactions || {},
        }));
    }, [messagesData]);

    // Mutations - hooks must be called unconditionally (React rules)
    const sendMessageMutation = useMutation(api.messages.sendMessage);
    const editMessageMutation = useMutation(api.messages.editMessage);
    const deleteMessageMutation = useMutation(api.messages.deleteMessage);
    const addReactionMutation = useMutation(api.messages.addReaction);
    const removeReactionMutation = useMutation(api.messages.removeReaction);
    const updateConversationMutation = useMutation(api.conversations.updateConversation);
    const updateUnreadCountMutation = useMutation(api.conversations.updateUnreadCount);

    // Auto-scroll to bottom and mark messages as read
    useEffect(() => {
        if (messagesEndRef.current && messages.length > 0) {
            messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
        }
    }, [messages]);

    // Mark messages as read when viewing
    // Use a ref to track the last message count to prevent infinite loops
    const lastMarkedCountRef = useRef(0);

    useEffect(() => {
        if (chatId && userId && messages.length > 0) {
            // Only mark as read if the message count actually changed
            // This prevents infinite loops from markAsRead triggering re-renders
            const currentMessageIds = messages.map((m: ChatMessage) => m.id);
            const currentCount = currentMessageIds.length;

            if (currentCount !== lastMarkedCountRef.current) {
                lastMarkedCountRef.current = currentCount;
                markAsRead(currentMessageIds);
            }
        }
    }, [chatId, userId, messages.length, markAsRead]);

    // Fetch link previews for messages
    useEffect(() => {
        messages.forEach((msg: ChatMessage) => {
            if (msg.b) {
                const urlMatch = msg.b.match(/(https?:\/\/[^\s]+)/);
                if (urlMatch) {
                    const url = urlMatch[0];
                    if (!linkPreviewData[msg.id]) {
                        getLinkPreview(url)
                            .then(data => setLinkPreviewData((prev: Record<string, any>) => ({ ...prev, [msg.id]: data })))
                            .catch((e: any) => console.error(e));
                    }
                }
            }
        });
    }, [messages]);

    // --- REACTION HANDLER ---
    const handleReaction = async (messageId: string, emoji: string) => {
        if (!chatId || !userId || !isConvexAvailable()) return;

        try {
            // Check if user already has this reaction
            const message = messages.find((m: ChatMessage) => m.id === messageId);
            if (!message) return;

            const reactionData = message.reactions?.[emoji];
            const hasReaction = Array.isArray(reactionData)
                ? reactionData.includes(userId)
                : (reactionData?.[userId] === true);

            if (hasReaction) {
                await removeReactionMutation({ messageId: messageId as any, userId: userId, emoji });
            } else {
                await addReactionMutation({ messageId: messageId as any, userId: userId, emoji });
            }
        } catch (error) {
            console.error('Reaction error:', error);
        }
    };

    // --- FORWARD HANDLER ---
    const handleForward = async (message: ChatMessage, targetChatIds: string[]) => {
        if (!isConvexAvailable() || !sendMessageMutation || !updateConversationMutation) {
            alert("Chat functionality is not available. Convex is not configured.");
            return;
        }

        // Get active profile data for display name and photo
        const activeRole = userData?.activeProfileRole || userData?.accountTypes?.[0] || 'Fan';
        const mongoSubprofile = userData?.subprofiles?.[activeRole];
        const legacySubprofile = subProfiles?.[activeRole];
        const activeProfile = mongoSubprofile || legacySubprofile || {};

        const senderName = activeProfile?.display_name ||
            activeProfile?.displayName ||
            userData?.displayName ||
            userData?.effectiveDisplayName ||
            userData?.firstName ||
            'User';

        const senderPhoto = activeProfile?.photo_url ||
            userData?.photoURL ||
            user?.imageUrl ||
            undefined;

        const forwardText = message.b || '';
        const forwardMedia = message.media || null;

        for (const targetChatId of targetChatIds) {
            try {
                // GUARD: Ensure no nulls are passed to optional fields
                await sendMessageMutation({
                    chatId: targetChatId,
                    senderId: userId,
                    senderName: senderName,
                    senderPhoto: senderPhoto, // Strict undefined
                    content: `↪ Forwarded: ${forwardText}`,
                    media: forwardMedia || undefined, // Strict undefined
                });

                // Update conversation
                const targetConvo = conversations?.find((c: any) => c.id === targetChatId);
                const summary = forwardText || (forwardMedia ? `Forwarded ${forwardMedia.type}` : 'Forwarded message');

                await updateConversationMutation({
                    userId: userId,
                    chatId: targetChatId,
                    lastMessage: `↪ ${summary}`,
                    lastMessageTime: Date.now(),
                    lastSenderId: userId,
                    chatName: targetConvo?.name || targetConvo?.n,
                    chatPhoto: targetConvo?.photo || '',
                    chatType: targetConvo?.type || 'direct',
                    otherUserId: targetConvo?.uid,
                });
            } catch (error) {
                console.error('Forward error for chat:', targetChatId, error);
            }
        }
    };

    // --- SEND LOGIC ---
    const sendMessage = async (text: string, mediaData: any) => {
        if (!chatId || (!text?.trim() && !mediaData) || !isConvexAvailable() || !sendMessageMutation || !editMessageMutation || !updateConversationMutation || !updateUnreadCountMutation) return;

        let msgText = text ? text.trim() : '';
        if (msgText.length === 0 && mediaData) {
            msgText = mediaData.type === 'image' ? '📷 Image' :
                mediaData.type === 'video' ? '🎥 Video' :
                    mediaData.type === 'audio' ? '🎵 Audio' : '📎 File';
        }

        // Handle edit mode
        if (editingMessage) {
            try {
                await editMessageMutation({
                    messageId: editingMessage.id,
                    content: msgText,
                    senderId: userId,
                });
                setEditingMessage(null);
                return;
            } catch (error) {
                console.error('Edit error:', error);
                return;
            }
        }

        try {
            // Get active profile data for display name and photo
            const activeRole = userData?.activeProfileRole || userData?.accountTypes?.[0] || 'Fan';
            const mongoSubprofile = userData?.subprofiles?.[activeRole];
            const legacySubprofile = subProfiles?.[activeRole];
            const activeProfile = mongoSubprofile || legacySubprofile || {};

            const senderName = activeProfile?.display_name ||
                activeProfile?.displayName ||
                userData?.displayName ||
                userData?.effectiveDisplayName ||
                userData?.firstName ||
                'User';

            const senderPhoto = activeProfile?.photo_url ||
                userData?.photoURL ||
                user?.imageUrl ||
                undefined;

            // Send message
            // GUARD: Ensure strictly undefined for null/empty optional fields
            await sendMessageMutation({
                chatId,
                senderId: userId,
                senderName: senderName,
                senderPhoto: senderPhoto, // undefined if null
                content: msgText || undefined,               // undefined if empty
                media: mediaData || undefined,               // undefined if null
                replyTo: replyingTo ? {
                    messageId: replyingTo.id,
                    text: replyingTo.b?.substring(0, 100) || 'Media',
                    sender: replyingTo.n || 'User',
                } : undefined,
            });

            // Update conversation for all recipients
            const summary = msgText || (mediaData ? `Sent ${mediaData.type}` : 'Message');
            let recipientIds: string[] = [];
            let otherUid = activeChat?.uid;

            if (!otherUid && activeChat?.type !== 'group' && chatId && chatId.includes('_')) {
                const parts = chatId.split('_');
                otherUid = parts.find((id: string) => id !== userId);
            }

            if (activeChat?.type === 'group') {
                // For group chats, use the queried members from chatMembers table
                // Include current user if not already in the list
                recipientIds = groupMemberIds.length > 0
                    ? [...new Set([userId, ...groupMemberIds])]
                    : [userId];
            } else if (otherUid) {
                recipientIds = [userId, otherUid];
            } else {
                recipientIds = [userId];
            }

            // Update conversations for all recipients
            for (const recipientUid of recipientIds) {
                await updateConversationMutation({
                    userId: recipientUid,
                    chatId,
                    lastMessage: summary,
                    lastMessageTime: Date.now(),
                    lastSenderId: userId,
                    chatName: activeChat?.type === 'group' ? chatName : (activeChat?.name || activeChat?.n),
                    chatPhoto: activeChat?.photo || '',
                    chatType: activeChat?.type || 'direct',
                    otherUserId: activeChat?.type === 'direct' ? (recipientUid === userId ? otherUid : userId) : undefined,
                });

                // Update unread count (increment for others, reset for sender)
                if (recipientUid === userId) {
                    await updateUnreadCountMutation({
                        userId: recipientUid,
                        chatId,
                        setTo: 0,
                    });
                } else {
                    await updateUnreadCountMutation({
                        userId: recipientUid,
                        chatId,
                        increment: 1,
                    });
                }
            }

            setReplyingTo(null);
        } catch (error) {
            console.error('Send message error:', error);
        }
    };

    // --- DELETE HANDLER ---
    const handleDelete = async (messageId: string, forEveryone: boolean = false) => {
        if (!chatId || !userId || !isConvexAvailable() || !deleteMessageMutation) return;

        try {
            await deleteMessageMutation({
                messageId,
                senderId: userId,
                forEveryone,
            });
        } catch (error) {
            console.error('Delete error:', error);
        }
    };

    // --- HEADER ---
    const ChatHeader = useMemo(() => (
        <div className="flex items-center justify-between p-4 border-b dark:border-gray-800 bg-white dark:bg-[#1f2128]">
            <div className="flex items-center gap-3 flex-1 min-w-0">
                <button
                    onClick={onBack}
                    className="md:hidden p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-lg transition-colors"
                >
                    <ArrowLeft className="w-5 h-5" />
                </button>

                <div
                    className="flex items-center gap-3 flex-1 min-w-0 cursor-pointer"
                    onClick={() => otherUserId && openPublicProfile?.(otherUserId, chatName)}
                >
                    <UserAvatar
                        src={activeChat?.photo || activeChat?.n?.photo || ''}
                        name={chatName}
                        size="md"
                    />
                    <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                            <h3 className="font-semibold text-gray-900 dark:text-white truncate">
                                {chatName}
                            </h3>
                            {activeChat?.type !== 'group' && (
                                <PresenceIndicator
                                    online={online}
                                    lastSeen={lastSeen}
                                    loading={presenceLoading}
                                />
                            )}
                        </div>
                        {activeChat?.type !== 'group' && (
                            <p className="text-xs text-gray-500 dark:text-gray-400">
                                {online ? 'Online' : lastSeen ? `Last seen ${formatLastSeen(lastSeen)}` : 'Offline'}
                            </p>
                        )}
                    </div>
                </div>
            </div>

            <button
                onClick={toggleDetails}
                className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-lg transition-colors"
            >
                <Info className="w-5 h-5 text-gray-600 dark:text-gray-400" />
            </button>
        </div>
    ), [activeChat, chatName, online, lastSeen, presenceLoading, otherUserId, onBack, toggleDetails, openPublicProfile]);

    // Format last seen helper
    const formatLastSeen = (timestamp: number): string => {
        if (!timestamp) return 'Never';
        const lastSeenMs = timestamp;
        const now = Date.now();
        const diffMs = now - lastSeenMs;
        const diffMins = Math.floor(diffMs / 60000);
        const diffHours = Math.floor(diffMins / 60);
        const diffDays = Math.floor(diffHours / 24);

        if (diffMins < 1) return 'Just now';
        if (diffMins < 60) return `${diffMins}m ago`;
        if (diffHours < 24) return `${diffHours}h ago`;
        if (diffDays < 7) return `${diffDays}d ago`;
        return new Date(lastSeenMs).toLocaleDateString();
    };

    // Early return for no active chat (after all hooks are called to maintain hook count)
    if (!activeChat || !chatId) {
        return (
            <div className="flex flex-col h-full bg-white dark:bg-[#1f2128] items-center justify-center text-gray-400">
                <div className="w-20 h-20 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center mb-4">
                    <Users size={64} className="text-gray-200 dark:text-gray-700 mb-2" />
                </div>
                <p>Select a conversation to start chatting</p>
            </div>
        );
    }

    return (
        <div className="flex flex-col h-full bg-white dark:bg-[#1f2128]">
            {ChatHeader}

            {/* Messages Area */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide">
                {messages.length === 0 ? (
                    <div className="flex items-center justify-center h-full text-gray-400">
                        <p>{t('noMessages')}. {t('startConversation')}!</p>
                    </div>
                ) : (
                    messages.map((message: ChatMessage, index: number) => {
                        const previousMessage = index > 0 ? messages[index - 1] : null;
                        const isCurrentUser = message.s === userId;
                        const isRead = isMessageRead(message.id);
                        const hasRead = hasCurrentUserRead(message.id);

                        return (
                            <MessageBubble
                                key={message.id}
                                message={message}
                                isCurrentUser={isCurrentUser}
                                previousMessage={previousMessage}
                                currentUserId={userId}
                                chatId={chatId}
                                linkPreviewData={linkPreviewData[message.id]}
                                messageStatus={isRead ? 'read' : hasRead ? 'delivered' : 'sent'}
                                onReaction={(emoji: string) => handleReaction(message.id, emoji)}
                                onReply={() => setReplyingTo(message)}
                                onEdit={() => setEditingMessage(message)}
                                onDelete={(forEveryone: boolean) => handleDelete(message.id, forEveryone)}
                                onForward={() => setForwardingMessage(message)}
                                onSeshNxLinkClick={(data: any) => setEmbedModal({ isOpen: true, url: '', previewData: data })}
                                onUserClick={() => message.s && openPublicProfile?.(message.s, message.n)}
                            />
                        );
                    })
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Chat Input */}
            <ChatInput
                activeChatId={chatId}
                uid={userId}
                onSend={sendMessage}
                replyingTo={replyingTo}
                editingMessage={editingMessage}
                onCancelReply={() => setReplyingTo(null)}
                onCancelEdit={() => setEditingMessage(null)}
                typingUsers={typingUsers}
                onTyping={setTyping}
                onStopTyping={clearTyping}
            />

            {/* Forward Modal */}
            {forwardingMessage && (
                <ForwardMessageModal
                    message={forwardingMessage}
                    conversations={conversations}
                    onClose={() => setForwardingMessage(null)}
                    onForward={handleForward}
                />
            )}

            {/* Embed Modal */}
            {embedModal.isOpen && (
                <SeshNxEmbedModal
                    url={embedModal.url}
                    previewData={embedModal.previewData}
                    onClose={() => setEmbedModal({ isOpen: false, url: '', previewData: null })}
                />
            )}
        </div>
    );
}
